int[] twoSum(int[] nums, int target) {
    Map<Integer,Integer> seen = new HashMap<>();
    for (int i = 0; i < nums.length; i++) {
        int diff = target - nums[i];
        if (seen.containsKey(diff)) return new int[]{seen.get(diff), i};
        seen.put(nums[i], i);
    }
    return new int[]{};
}

