python.answer:
def is_valid(s):
    stack = []
    mapping = {')':'(', '}':'{', ']':'['}
    for c in s:
        if c in mapping:
            top = stack.pop() if stack else '#'
            if mapping[c] != top: return False
        else:
            stack.append(c)
    return not stack

