bool isValid(char *s) {
    char stack[10001]; int top = -1;
    for (int i=0; s[i]; i++) {
        char c = s[i];
        if (c=='('||c=='['||c=='{') stack[++top] = c;
        else {
            if (top<0) return false;
            char t = stack[top--];
            if (c==')' && t!='(') return false;
            if (c==']' && t!='[') return false;
            if (c=='}' && t!='{') return false;
        }
    }
    return top == -1;
}

