python.answer:
def count_pairs(nums, target):
    from collections import Counter
    freq = Counter(nums)
    count = 0
    for n in list(freq):
        comp = target - n
        if comp in freq:
            if comp == n:
                count += freq[n] * (freq[n]-1) // 2
            elif comp > n:
                count += freq[n] * freq[comp]
    return count

