java.code:
boolean hasPair(int[] arr, int target) {
    Arrays.sort(arr);
    int left=0, right=arr.length;
    while(left<right){
        int s=arr[left]+arr[right];
        if(s==target) return true;
        else if(s<target) left++;
        else right--;
    }
    return false;
}

