int hasPair(int *arr, int n, int target) {
    // assume sorted
    int left=0, right=n;
    while(left<right){
        int s=arr[left]+arr[right];
        if(s==target) return 1;
        else if(s<target) left++;
        else right--;
    }
    return 0;
}

