String compress(String s) {
    StringBuilder sb=new StringBuilder();
    int i=0;
    while(i<s.length()){
        char c=s.charAt(i); int cnt=0;
        while(i<s.length()&&s.charAt(i)==c){cnt++;i++;}
        sb.append(c);
        if(cnt>1) sb.append(cnt);
    }
    return sb.length()<s.length()?sb.toString():s;
}

