void compress(char* s, char* out) {
    int i=0,k=0;
    while(s[i]){
        char c=s[i]; int cnt=0;
        while(s[i]==c){cnt++;i++;}
        out[k++]=c;
        if(cnt>1){char buf[12];sprintf(buf,"%d",cnt);for(int j=0;buf[j];j++) out[k++]=buf[j];}
    }
    out[k]='\0';
}

