def sorted_squares(nums):
    n = len(nums)
    res = [0] * n
    l, r, pos = 0, n-1, n-1
    while l <= r:
        if abs(nums[l]) > abs(nums[r]):
            res[pos] = nums[l]**2; l += 1
        else:
            res[pos] = nums[r]**2; r -= 1
        pos -= 1
    return res

