String longestPalindrome(String s) {
    String res="";
    for(int i=0;i<s.length();i++){
        for(int[] p:new int[][]{{i,i},{i,i+1}}){
            int l=p[0],r=p[1];
            while(l>=0&&r<s.length()&&s.charAt(l)==s.charAt(r)){l--;r++;}
            if(r-l-1>res.length()) res=s.substring(l+1,r);
        }
    }
    return res;
}

