char* longestPalindrome(char* s) {
    int n=strlen(s), start=0, maxLen=1;
    for(int i=0;i<n;i++){
        for(int odd=0;odd<=1;odd++){
            int l=i,r=i+odd;
            while(l>=0&&r<n&&s[l]==s[r]){l--;r++;}
            if(r-l-1>maxLen){maxLen=r-l-1;start=l+1;}
        }
    }
    char *res=malloc(maxLen+1);
    strncpy(res,s+start,maxLen);
    res[maxLen]='\0';
    return res;
}
